"""Tests for PipelineStateStorage and RunState."""from pathlib import Pathimport pytestfrom src.modules.project_pipeline.pipeline_state_storage import (    PipelineStateStorage,    RunState,    get_default_storage,)def test_get_current_initially_none() -> None:    storage = PipelineStateStorage()    assert storage.get_current() is Nonedef test_claim_returns_true_when_idle() -> None:    storage = PipelineStateStorage()    root = Path("/fake/project")    assert storage.claim(root) is True    current = storage.get_current()    assert current is not None    assert current.project_root == root    assert current.status == "running"def test_claim_returns_false_when_already_running() -> None:    storage = PipelineStateStorage()    root1 = Path("/fake/project1")    root2 = Path("/fake/project2")    assert storage.claim(root1) is True    assert storage.claim(root2) is False    assert storage.get_current() is not None    assert storage.get_current().project_root == root1def test_release_clears_current() -> None:    storage = PipelineStateStorage()    storage.claim(Path("/fake/project"))    storage.release()    assert storage.get_current() is Nonedef test_get_cancel_event_after_claim() -> None:    storage = PipelineStateStorage()    assert storage.get_cancel_event() is None    storage.claim(Path("/fake/project"))    event = storage.get_cancel_event()    assert event is not None    assert not event.is_set()    storage.release()    assert storage.get_cancel_event() is Nonedef test_request_cancel_sets_event() -> None:    storage = PipelineStateStorage()    storage.claim(Path("/fake/project"))    event = storage.get_cancel_event()    assert event is not None    storage.request_cancel()    assert event.is_set()def test_request_cancel_when_idle_does_nothing() -> None:    storage = PipelineStateStorage()    storage.request_cancel()    assert storage.get_current() is Nonedef test_set_status_updates_current_run_state(tmp_path: Path) -> None:    storage = PipelineStateStorage()    assert storage.claim(tmp_path) is True    assert storage.get_current() is not None    assert storage.get_current().status == "running"    storage.set_status("completed")    assert storage.get_current() is not None    assert storage.get_current().status == "completed"    storage.set_status("failed")    assert storage.get_current().status == "failed"    storage.release()    assert storage.get_current() is Nonedef test_get_default_storage_returns_singleton() -> None:    a = get_default_storage()    b = get_default_storage()    assert a is b